import { getDocument, isShadowRoot } from '@zag-js/dom-query'
import { Children, type PropsWithChildren, type RefObject, useEffect, useState, useSyncExternalStore } from 'react'
import { createPortal } from 'react-dom'
import { type RootNode, useEnvironmentContext } from '../../providers/index.ts'

export interface PortalProps {
  disabled?: boolean | undefined
  container?: RefObject<HTMLElement | null> | undefined
}

export const Portal = (props: PropsWithChildren<PortalProps>) => {
  const { children, disabled } = props
  const [container, setContainer] = useState(props.container?.current)
  const isServer = useSyncExternalStore(
    subscribe,
    () => false,
    () => true,
  )
  const { getRootNode } = useEnvironmentContext()

  useEffect(() => {
    setContainer(() => props.container?.current)
  }, [props.container])

  if (isServer || disabled) return <>{children}</>

  const mountNode = container ?? getPortalNode(getRootNode)
  return <>{Children.map(children, (child) => createPortal(child, mountNode))}</>
}

const getPortalNode = (cb: () => RootNode) => {
  const node = cb?.()
  const rootNode = node.getRootNode()
  if (isShadowRoot(rootNode)) return rootNode
  return getDocument(node).body
}

const subscribe = () => () => {}

import { CacheProvider } from "@emotion/react"
import createEmotionServer from "@emotion/server/create-instance"
import { renderToString } from "react-dom/server"
import { Provider } from "../components/ui/provider"
import { createEmotionCache } from "./emotion-cache"

export function createEmotion() {
  const cache = createEmotionCache()
  const server = createEmotionServer(cache)

  function injectStyles(html: string) {
    const { styles } = server.extractCriticalToChunks(html)

    let stylesHTML = ""

    styles.forEach(({ key, ids, css }) => {
      const emotionKey = `${key} ${ids.join(" ")}`
      const newStyleTag = `<style data-emotion="${emotionKey}">${css}</style>`
      stylesHTML = `${stylesHTML}${newStyleTag}`
    })

    // add the emotion style tags after the insertion point meta tag
    const markup = html.replace(
      /<meta(\s)*name="emotion-insertion-point"(\s)*content="emotion-insertion-point"(\s)*\/>/,
      `<meta name="emotion-insertion-point" content="emotion-insertion-point"/>${stylesHTML}`,
    )

    return markup
  }

  function _renderToString(element: React.ReactNode) {
    return renderToString(
      <CacheProvider value={cache}>
        <Provider>{element}</Provider>
      </CacheProvider>,
    )
  }

  return {
    server,
    cache,
    injectStyles,
    renderToString: _renderToString,
  }
}

import * as React from 'react'

import {useSelect} from '../../src'
import {colors} from '../utils'

export default function DropdownSelect() {
  const {
    isOpen,
    selectedItem,
    getToggleButtonProps,
    getLabelProps,
    getMenuProps,
    highlightedIndex,
    getItemProps,
  } = useSelect({items: colors})

  return (
    <div className="container">
      <label
        style={{
          fontWeight: 'bolder',
          color: selectedItem ? selectedItem : 'black',
        }}
        {...getLabelProps()}
      >
        Choose an element:
      </label>
      <div
        style={{
          padding: '4px',
          textAlign: 'center',
          border: '1px solid black',
          backgroundColor: 'lightgray',
          cursor: 'pointer',
        }}
        {...getToggleButtonProps()}
      >
        {selectedItem ?? 'Elements'}
        {isOpen ? <>&#8593;</> : <>&#8595;</>}
      </div>
      <ul {...getMenuProps()} className="menu">
        {isOpen
          ? colors.map((item, index) => (
              <li
                style={{
                  padding: '4px',
                  backgroundColor:
                    highlightedIndex === index ? '#bde4ff' : undefined,
                }}
                key={`${item}${index}`}
                {...getItemProps({
                  item,
                  index,
                  'data-testid': `downshift-item-${index}`,
                })}
              >
                {item}
              </li>
            ))
          : null}
      </ul>
    </div>
  )
}

import * as React from 'react'

import {useTagGroup} from '../../src'
import {colors} from '../utils'


export default function TagGroup() {
  const initialItems = colors.slice(0, 5)
  const {
    addItem,
    getTagProps,
    getTagRemoveProps,
    getTagGroupProps,
    items,
    activeIndex,
  } = useTagGroup({initialItems})
  const itemsToAdd = colors.filter(color => !items.includes(color))

  return (
    <div>
      <div
        {...getTagGroupProps({'aria-label': 'colors example'})}
        className="tag-group"
      >
        {items.map((color, index) => (
          <span
            className={`${index === activeIndex ? 'selected-tag' : ''} tag`}
            key={color}
            {...getTagProps({index, 'aria-label': color})}
          >
            {color}
            <button
              className="tag-remove-button"
              type="button"
              {...getTagRemoveProps({index, 'aria-label': 'remove'})}
            >
              &#10005;
            </button>
          </span>
        ))}
      </div>
      <div>Add more items:</div>
      <ul>
        {itemsToAdd.map(item => (
          <li key={item}>
            <button
              className="item-to-add"
              tabIndex={0}
              onClick={() => {
                addItem(item)
              }}
              onKeyDown={({key}) => {
                key === 'Enter' && addItem(item)
              }}
            >
              {item}
            </button>
          </li>
        ))}
      </ul>
    </div>
  )
}

import type { TableData } from './Table';
import {
  TableCaption,
  TableTbody,
  TableTd,
  TableTfoot,
  TableTh,
  TableThead,
  TableTr,
} from './Table.components';

export interface TableDataRendererProps {
  data: TableData;
}

export function TableDataRenderer({ data }: TableDataRendererProps) {
  return (
    <>
      {data.caption && <TableCaption>{data.caption}</TableCaption>}

      {data.head && (
        <TableThead>
          <TableTr>
            {data.head.map((item, index) => (
              <TableTh key={index}>{item}</TableTh>
            ))}
          </TableTr>
        </TableThead>
      )}

      {data.body && (
        <TableTbody>
          {data.body.map((row, rowIndex) => (
            <TableTr key={rowIndex}>
              {row.map((item, index) => (
                <TableTd key={index}>{item}</TableTd>
              ))}
            </TableTr>
          ))}
        </TableTbody>
      )}

      {data.foot && (
        <TableTfoot>
          <TableTr>
            {data.foot.map((item, index) => (
              <TableTh key={index}>{item}</TableTh>
            ))}
          </TableTr>
        </TableTfoot>
      )}
    </>
  );
}

