import type {
  Atom,
  ExtractAtomArgs,
  ExtractAtomResult,
  ExtractAtomValue,
  PrimitiveAtom,
  SetStateAction,
  WritableAtom,
} from '../vanilla.ts'
import { useAtomValue } from './useAtomValue.ts'
import { useSetAtom } from './useSetAtom.ts'

type SetAtom<Args extends unknown[], Result> = (...args: Args) => Result

type Options = Parameters<typeof useAtomValue>[1]

export function useAtom<Value, Args extends unknown[], Result>(
  atom: WritableAtom<Value, Args, Result>,
  options?: Options,
): [Awaited<Value>, SetAtom<Args, Result>]

export function useAtom<Value>(
  atom: PrimitiveAtom<Value>,
  options?: Options,
): [Awaited<Value>, SetAtom<[SetStateAction<Value>], void>]

export function useAtom<Value>(
  atom: Atom<Value>,
  options?: Options,
): [Awaited<Value>, never]

export function useAtom<
  AtomType extends WritableAtom<unknown, never[], unknown>,
>(
  atom: AtomType,
  options?: Options,
): [
  Awaited<ExtractAtomValue<AtomType>>,
  SetAtom<ExtractAtomArgs<AtomType>, ExtractAtomResult<AtomType>>,
]

export function useAtom<AtomType extends Atom<unknown>>(
  atom: AtomType,
  options?: Options,
): [Awaited<ExtractAtomValue<AtomType>>, never]

export function useAtom<Value, Args extends unknown[], Result>(
  atom: Atom<Value> | WritableAtom<Value, Args, Result>,
  options?: Options,
) {
  return [
    useAtomValue(atom, options),
    // We do wrong type assertion here, which results in throwing an error.
    useSetAtom(atom as WritableAtom<Value, Args, Result>, options),
  ]
}

import { atom } from '../../vanilla.ts'
import type { WritableAtom } from '../../vanilla.ts'
import { RESET } from './constants.ts'

type Read<Value, Args extends unknown[], Result> = WritableAtom<
  Value,
  Args,
  Result
>['read']

type DefaultSetStateAction<Value> =
  | Value
  | typeof RESET
  | ((prev: Value) => Value | typeof RESET)

export function atomWithDefault<Value>(
  getDefault: Read<Value, [DefaultSetStateAction<Value>], void>,
): WritableAtom<Value, [DefaultSetStateAction<Value>], void> {
  const EMPTY = Symbol()
  const overwrittenAtom = atom<Value | typeof EMPTY>(EMPTY)

  if (import.meta.env?.MODE !== 'production') {
    overwrittenAtom.debugPrivate = true
  }

  const anAtom: WritableAtom<Value, [DefaultSetStateAction<Value>], void> =
    atom(
      (get, options) => {
        const overwritten = get(overwrittenAtom)
        if (overwritten !== EMPTY) {
          return overwritten
        }
        return getDefault(get, options)
      },
      (get, set, update) => {
        const newValue =
          typeof update === 'function'
            ? (update as (prev: Value) => Value)(get(anAtom))
            : update
        set(overwrittenAtom, newValue === RESET ? EMPTY : newValue)
      },
    )
  return anAtom
}

import { atom } from '../../vanilla.ts'
import type { WritableAtom } from '../../vanilla.ts'

type Read<Value, Args extends unknown[], Result> = WritableAtom<
  Value,
  Args,
  Result
>['read']
type Write<Value, Args extends unknown[], Result> = WritableAtom<
  Value,
  Args,
  Result
>['write']

export function atomWithRefresh<Value, Args extends unknown[], Result>(
  read: Read<Value, Args, Result>,
  write: Write<Value, Args, Result>,
): WritableAtom<Value, Args | [], Result | void>

export function atomWithRefresh<Value>(
  read: Read<Value, [], void>,
): WritableAtom<Value, [], void>

export function atomWithRefresh<Value, Args extends unknown[], Result>(
  read: Read<Value, Args, Result>,
  write?: Write<Value, Args, Result>,
) {
  const refreshAtom = atom(0)
  if (import.meta.env?.MODE !== 'production') {
    refreshAtom.debugPrivate = true
  }
  return atom(
    (get, options) => {
      get(refreshAtom)
      return read(get, options as never)
    },
    (get, set, ...args: Args) => {
      if (args.length === 0) {
        set(refreshAtom, (c) => c + 1)
      } else if (write) {
        return write(get, set, ...args)
      } else if (import.meta.env?.MODE !== 'production') {
        throw new Error('refresh must be called without arguments')
      }
    },
  )
}

const _setFieldArray: BatchFieldArrayUpdate = (
  name,
  values = [],
  method,
  args,
  shouldSetValues = true,
  shouldUpdateFieldsAndState = true,
) => {
  if (args && method && !_options.disabled) {
    _state.action = true;
    if (shouldUpdateFieldsAndState && Array.isArray(get(_fields, name))) {
      const fieldValues = method(get(_fields, name), args.argA, args.argB);
      shouldSetValues && set(_fields, name, fieldValues);
    }

    if (
      shouldUpdateFieldsAndState &&
      Array.isArray(get(_formState.errors, name))
    ) {
      const errors = method(
        get(_formState.errors, name),
        args.argA,
        args.argB,
      );
      shouldSetValues && set(_formState.errors, name, errors);
      unsetEmptyArray(_formState.errors, name);
    }

    if (
      (_proxyFormState.touchedFields ||
        _proxySubscribeFormState.touchedFields) &&
      shouldUpdateFieldsAndState &&
      Array.isArray(get(_formState.touchedFields, name))
    ) {
      const touchedFields = method(
        get(_formState.touchedFields, name),
        args.argA,
        args.argB,
      );
      shouldSetValues && set(_formState.touchedFields, name, touchedFields);
    }

    if (_proxyFormState.dirtyFields || _proxySubscribeFormState.dirtyFields) {
      _updateDirtyFields();
    }

    _subjects.state.next({
      name,
      isDirty: _getDirty(name, values),
      dirtyFields: _formState.dirtyFields,
      errors: _formState.errors,
      isValid: _formState.isValid,
    });
  } else {
    set(_formValues, name, values);
  }
};

const shouldRenderByError = (
  name: InternalFieldName,
  isValid?: boolean,
  error?: FieldError,
  fieldState?: {
    dirty?: FieldNamesMarkedBoolean<TFieldValues>;
    isDirty?: boolean;
    touched?: FieldNamesMarkedBoolean<TFieldValues>;
  },
) => {
  const previousFieldError = get(_formState.errors, name);
  const shouldUpdateValid =
    (_proxyFormState.isValid || _proxySubscribeFormState.isValid) &&
    isBoolean(isValid) &&
    _formState.isValid !== isValid;

  if (_options.delayError && error) {
    delayErrorCallback = debounce(() => updateErrors(name, error));
    delayErrorCallback(_options.delayError);
  } else {
    clearTimeout(timer);
    delayErrorCallback = null;
    error
      ? set(_formState.errors, name, error)
      : unset(_formState.errors, name);
  }

  if (
    (error ? !deepEqual(previousFieldError, error) : previousFieldError) ||
    !isEmptyObject(fieldState) ||
    shouldUpdateValid
  ) {
    const updatedFormState = {
      ...fieldState,
      ...(shouldUpdateValid && isBoolean(isValid) ? { isValid } : {}),
      errors: _formState.errors,
      name,
    };

    _formState = {
      ..._formState,
      ...updatedFormState,
    };

    _subjects.state.next(updatedFormState);
  }
};

import * as React from 'react'

import {generateId} from '../../../utils'

type UseElementIdsProps = {
  id?: string
  tagGroupId?: string
  getTagId?: (index: number) => string
}

type UseElementIdsReturnValue = {
  tagGroupId: string
  getTagId: (index: number) => string
}

// https://github.com/downshift-js/downshift/issues/1674#issuecomment-3924320872
const SafeReact = {...React}
const reactUseId = SafeReact.useId

// istanbul ignore next
export const useElementIds: (
  props: UseElementIdsProps,
) => UseElementIdsReturnValue =
  typeof reactUseId === 'function' ? useElementIdsR18 : useElementIdsLegacy

function useElementIdsR18({
  id,
  tagGroupId,
  getTagId,
}: UseElementIdsProps): UseElementIdsReturnValue {
  const reactId = `downshift-${reactUseId()}`
  if (!id) {
    id = reactId
  }

  const elementIds = React.useMemo(
    () => ({
      tagGroupId: tagGroupId ?? `${id}-tag-group`,
      getTagId: getTagId ?? (index => `${id}-tag-${index}`),
    }),
    [getTagId, id, tagGroupId],
  )

  return elementIds
}

function useElementIdsLegacy({
  id,
  getTagId,
  tagGroupId,
}: UseElementIdsProps): UseElementIdsReturnValue {
  const baseIdRef = React.useRef(id ?? `downshift-${generateId()}`)
  const baseId = baseIdRef.current

  const elementIds = React.useMemo(
    () => ({
      tagGroupId: tagGroupId ?? `${baseId}-tag-group`,
      getTagId: getTagId ?? (index => `${baseId}-tag-${index}`),
    }),
    [getTagId, baseId, tagGroupId],
  )

  return elementIds
}

