import * as React from 'react';
import {
  forwardRef,
  MutableRefObject,
  ReactElement,
  RefAttributes,
} from 'react';
import Select from './Select';
import { GroupBase } from './types';
import useAsync, { AsyncAdditionalProps } from './useAsync';
import useStateManager, { StateManagerProps } from './useStateManager';
import useCreatable, { CreatableAdditionalProps } from './useCreatable';

export type AsyncCreatableProps<
  Option,
  IsMulti extends boolean,
  Group extends GroupBase<Option>
> = StateManagerProps<Option, IsMulti, Group> &
  CreatableAdditionalProps<Option, Group> &
  AsyncAdditionalProps<Option, Group>;

type AsyncCreatableSelect = <
  Option = unknown,
  IsMulti extends boolean = false,
  Group extends GroupBase<Option> = GroupBase<Option>
>(
  props: AsyncCreatableProps<Option, IsMulti, Group> &
    RefAttributes<Select<Option, IsMulti, Group>>
) => ReactElement;

const AsyncCreatableSelect = forwardRef(
  <Option, IsMulti extends boolean, Group extends GroupBase<Option>>(
    props: AsyncCreatableProps<Option, IsMulti, Group>,
    ref:
      | ((instance: Select<Option, IsMulti, Group> | null) => void)
      | MutableRefObject<Select<Option, IsMulti, Group> | null>
      | null
  ) => {
    const stateManagerProps = useAsync(props);
    const creatableProps = useStateManager(stateManagerProps);
    const selectProps = useCreatable(creatableProps);

    return <Select ref={ref} {...selectProps} />;
  }
) as AsyncCreatableSelect;

export default AsyncCreatableSelect;

import { getHeatColor } from './get-heat-color/get-heat-color';
import { HeatmapWeeksSharedProps } from './HeatmapWeeks.types';

export function HeatmapWeeks({
  data,
  datesRange,
  rectSize,
  gap,
  rectRadius,
  min,
  max,
  colors,
  withTooltip,
  setHoveredRect,
  getRectProps,
  getStyles,
}: HeatmapWeeksSharedProps) {
  const rectSizeWithGap = rectSize + gap;

  return (
    <>
      {datesRange.map((week, weekIndex) => {
        // Original simple logic without month splitting
        const days = week.map((date, dayIndex) => {
          if (!date) {
            return null;
          }

          const hasValue = date in data && data[date] !== null;
          const rectValue = hasValue ? data[date] : null;

          return (
            <rect
              key={date}
              width={rectSize}
              height={rectSize}
              x={gap}
              y={dayIndex * rectSizeWithGap + gap}
              rx={rectRadius}
              data-empty={!hasValue || undefined}
              fill={hasValue ? getHeatColor({ value: data[date], min, max, colors }) : undefined}
              onPointerEnter={
                withTooltip ? () => setHoveredRect({ date, value: rectValue }) : undefined
              }
              {...getRectProps?.({ date, value: rectValue })}
              {...getStyles('rect')}
            />
          );
        });

        return (
          <g
            key={weekIndex}
            transform={`translate(${weekIndex * rectSizeWithGap}, 0)`}
            data-id="week"
          >
            {days}
          </g>
        );
      })}
    </>
  );
}

const encoder = /* @__PURE__ */ new TextEncoder();

export const sign = async (value: string, secret: string): Promise<string> => {
  let data = encoder.encode(value);
  let key = await createKey(secret, ["sign"]);
  let signature = await crypto.subtle.sign("HMAC", key, data);
  let hash = btoa(String.fromCharCode(...new Uint8Array(signature))).replace(
    /=+$/,
    "",
  );

  return value + "." + hash;
};

export const unsign = async (
  cookie: string,
  secret: string,
): Promise<string | false> => {
  let index = cookie.lastIndexOf(".");
  let value = cookie.slice(0, index);
  let hash = cookie.slice(index + 1);

  let data = encoder.encode(value);

  let key = await createKey(secret, ["verify"]);
  try {
    let signature = byteStringToUint8Array(atob(hash));
    let valid = await crypto.subtle.verify("HMAC", key, signature, data);

    return valid ? value : false;
  } catch (
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    e
  ) {
    // atob will throw a DOMException with name === 'InvalidCharacterError'
    // if the signature contains a non-base64 character, which should just
    // be treated as an invalid signature.
    return false;
  }
};

const createKey = async (
  secret: string,
  usages: CryptoKey["usages"],
): Promise<CryptoKey> =>
  crypto.subtle.importKey(
    "raw",
    encoder.encode(secret),
    { name: "HMAC", hash: "SHA-256" },
    false,
    usages,
  );

function byteStringToUint8Array(byteString: string): Uint8Array {
  let array = new Uint8Array(byteString.length);

  for (let i = 0; i < byteString.length; i++) {
    array[i] = byteString.charCodeAt(i);
  }

  return array;
}

import { TimePickerAmPmLabels, TimePickerFormat } from '../../TimePicker.types';
import { padTime } from '../pad-time/pad-time';

interface Time12HourFormat {
  hours: number;
  minutes: number;
  seconds: number | null;
  withSeconds: boolean;
  amPm: string;
  amPmLabels: TimePickerAmPmLabels;
}

function convertTo24HourFormat({
  hours,
  minutes,
  seconds,
  amPm,
  amPmLabels,
  withSeconds,
}: Time12HourFormat): string {
  let _hours = hours;

  if (amPm === amPmLabels.pm && hours !== 12) {
    _hours += 12;
  } else if (amPm === amPmLabels.am && hours === 12) {
    _hours = 0;
  }

  return `${padTime(_hours)}:${padTime(minutes)}${withSeconds ? `:${padTime(seconds || 0)}` : ''}`;
}

interface GetTimeStringInput {
  hours: number | null;
  minutes: number | null;
  seconds: number | null;
  format: TimePickerFormat;
  withSeconds: boolean;
  amPm: string | null;
  amPmLabels: TimePickerAmPmLabels;
}

export function getTimeString({
  hours,
  minutes,
  seconds,
  format,
  withSeconds,
  amPm,
  amPmLabels,
}: GetTimeStringInput) {
  if (hours === null || minutes === null) {
    return { valid: false, value: '' };
  }

  if (withSeconds && seconds === null) {
    return { valid: false, value: '' };
  }

  if (format === '24h') {
    const value = `${padTime(hours)}:${padTime(minutes)}${withSeconds ? `:${padTime(seconds!)}` : ''}`;
    return { valid: true, value };
  }

  if (amPm === null) {
    return { valid: false, value: '' };
  }

  return {
    valid: true,
    value: convertTo24HourFormat({ hours, minutes, seconds, amPm, amPmLabels, withSeconds }),
  };
}

import chroma from 'chroma-js';

const LIGHTNESS_MAP = [0.96, 0.907, 0.805, 0.697, 0.605, 0.547, 0.518, 0.445, 0.395, 0.34];
const SATURATION_MAP = [0.32, 0.16, 0.08, 0.04, 0, 0, 0.04, 0.08, 0.16, 0.32];

function getClosestLightness(colorObject: chroma.Color) {
  const lightnessGoal = colorObject.get('hsl.l');
  return LIGHTNESS_MAP.reduce((prev, curr) =>
    Math.abs(curr - lightnessGoal) < Math.abs(prev - lightnessGoal) ? curr : prev
  );
}

export function generateColorsMap(color: string) {
  const colorObject = chroma(color);
  const closestLightness = getClosestLightness(colorObject);
  const baseColorIndex = LIGHTNESS_MAP.findIndex((l) => l === closestLightness);

  const colors = LIGHTNESS_MAP.map((l) => colorObject.set('hsl.l', l))
    .map((c) => chroma(c))
    .map((c, i) => {
      const saturationDelta = SATURATION_MAP[i] - SATURATION_MAP[baseColorIndex];
      return saturationDelta >= 0
        ? c.saturate(saturationDelta)
        : c.desaturate(saturationDelta * -1);
    });

  colors[baseColorIndex] = chroma(color);

  return { baseColorIndex, colors };
}

export type MantineColorsTuple = readonly [
  string,
  string,
  string,
  string,
  string,
  string,
  string,
  string,
  string,
  string,
  ...string[],
];

export function generateColors(color: string) {
  return generateColorsMap(color).colors.map((c) => c.hex()) as unknown as MantineColorsTuple;
}
